-- Saved-list import: stage 3K rows once, run UPDATE then INSERT in
-- one transaction. Idempotent — UPDATE merges into existing saved_lists
-- without dupes; INSERT skips rows whose norm_name already matches a pin.
BEGIN;

CREATE TEMP TABLE _saved_import (
  norm_name text PRIMARY KEY,
  list_arr text[] NOT NULL,
  display_name text NOT NULL,
  note text
) ON COMMIT DROP;

