-- 1) Append list memberships to matched existing pins. Notes copy in only
--    when the pin's personal_notes column is empty.
WITH unioned AS (
  SELECT p.id AS pin_id, array_agg(DISTINCT l) AS new_lists,
         max(NULLIF(s.note, '')) FILTER (WHERE s.note <> '') AS first_note
  FROM _saved_import s
  JOIN pins p ON p.norm_name = s.norm_name
  CROSS JOIN LATERAL unnest(s.list_arr) AS l
  GROUP BY p.id
)
UPDATE pins p
SET saved_lists = (
      SELECT array_agg(DISTINCT x ORDER BY x)
      FROM unnest(p.saved_lists || u.new_lists) AS x
    ),
    personal_notes = COALESCE(NULLIF(p.personal_notes, ''), u.first_note),
    updated_at = now()
FROM unioned u
WHERE p.id = u.pin_id;

-- 2) Insert draft pins for staging rows that didn't match any existing pin.
--    No coords, no slug, source='google-saved-list', visited=false.
INSERT INTO pins (
  name, source, saved_lists, personal_notes, visited,
  city_names, states_names, tags, lists, images, hours_details, price_details, enrichment_status
)
SELECT s.display_name, 'google-saved-list', s.list_arr,
       NULLIF(s.note, ''), FALSE,
       ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[],
       '[]'::jsonb, '{}'::jsonb, '{}'::jsonb, 'unverified'
FROM _saved_import s
WHERE NOT EXISTS (SELECT 1 FROM pins p WHERE p.norm_name = s.norm_name);

COMMIT;

-- Final counts so we can verify the migration landed.
SELECT
  COUNT(*) FILTER (WHERE source = 'google-saved-list') AS new_draft_pins,
  COUNT(*) FILTER (WHERE array_length(saved_lists, 1) > 0) AS pins_with_saved_lists,
  COUNT(*) AS total_pins
FROM pins;